// Tests for AlacDecoder (C# port of the Apple ALAC decoder, Apache-2.0).
//
// The compressed golden vectors below were produced with ffmpeg 8.1.2 on
// 2026-07-16 and are self-contained — ffmpeg is NOT needed at test runtime:
//
//   1. A deterministic 2 s stereo tone (440 Hz + 997 Hz mix, 30000 amplitude,
//      exact formulas in alac-port-notes.md) was synthesized as s16le/44100/2ch
//      and encoded with:
//        ffmpeg -f s16le -ar 44100 -ac 2 -i tone.raw -c:a alac -frame_size 352 out352.caf
//      (`-frame_size` is ignored by ffmpeg's ALAC encoder — the CAF 'desc'
//      chunk reports framesPerPacket=4096 — so the vectors use the cookie's
//      frameLength of 4096, per-spec identical to AirPlay's 352 except for size.)
//   2. The CAF was parsed (caff header; 'desc'; 'kuki' = magic cookie;
//      'pakt' packet table with BER-style variable-length sizes; 'data')
//      to extract the cookie and the individual ALAC packets.
//   3. ffmpeg's own decode (`ffmpeg -i out352.caf -f s16le -acodec pcm_s16le
//      ref.raw`) was verified byte-identical to the original tone over its
//      full 345152-byte length (ffmpeg's CAF demuxer over-trims the final
//      partial packet, so its output is a strict prefix of the input), and
//      the AlacDecoder output for all 22 packets was verified byte-identical
//      to the complete 352800-byte original. The expected PCM constants are
//      slices of that mutually-verified stream.
//   4. Same procedure for the mono (SCE) vector, from a 1 s mono tone
//      (11 packets, 88200 bytes, also byte-identical end to end).
//
// Embedded: stereo CAF packet 0 (full 4096-sample CPE frame), stereo packet 21
// (final 2184-sample partial frame — exercises the partial-frame length path),
// and mono packet 0 (full SCE frame). Both kuki cookies are the 48-byte
// 'frma'+'alac'-wrapped form exactly as ffmpeg wrote them.

using Streamsemble.AirPlay.Receiver.Audio;
using Xunit;

namespace Streamsemble.AirPlay.Tests;

public sealed class AlacDecoderTests
{
    // ALACSpecificConfig used by the Streamsemble AirPlay sender (raw 24-byte
    // form): frameLength=352, bitDepth=16, pb=40, mb=10, kb=14, ch=2,
    // maxRun=255, sampleRate=44100.
    private const string AirPlayCookieHex = "000001600010280A0E0200FF00000000000000000000AC44";

    // ------------------------------------------------------------------
    // (a) Verbatim round-trip against an inline replica of AlacPacker
    // ------------------------------------------------------------------

    [Fact]
    public void VerbatimPacket_RoundTripsByteIdentical()
    {
        var pcm = DeterministicPcm(352 * 2); // 352 stereo sample pairs
        var packet = PackVerbatim(pcm);

        var decoder = new AlacDecoder(Convert.FromHexString(AirPlayCookieHex));
        Assert.Equal(352, decoder.FrameLength);
        Assert.Equal(2, decoder.Channels);
        Assert.Equal(44100, decoder.SampleRate);

        var decoded = new byte[decoder.MaxBytesPerPacket];
        var written = decoder.DecodePacket(packet, decoded);

        Assert.Equal(pcm.Length, written);
        Assert.Equal(pcm, decoded.AsSpan(0, written).ToArray());
    }

    [Fact]
    public void VerbatimPacket_SilenceAndFullScale()
    {
        // Edge amplitudes: min/max/zero patterns survive the BE swap + sign handling.
        var pcm = new byte[352 * 4];
        for (var s = 0; s < 352; s++)
        {
            var v = (s % 3) switch { 0 => short.MinValue, 1 => short.MaxValue, _ => (short)0 };
            BitConverter.TryWriteBytes(pcm.AsSpan(s * 4), v);
            BitConverter.TryWriteBytes(pcm.AsSpan(s * 4 + 2), (short)-v);
        }

        var decoder = new AlacDecoder(Convert.FromHexString(AirPlayCookieHex));
        var decoded = new byte[decoder.MaxBytesPerPacket];
        var written = decoder.DecodePacket(PackVerbatim(pcm), decoded);

        Assert.Equal(pcm.Length, written);
        Assert.Equal(pcm, decoded.AsSpan(0, written).ToArray());
    }

    // ------------------------------------------------------------------
    // (b) Compressed golden vectors (ffmpeg-encoded, cross-verified)
    // ------------------------------------------------------------------

    [Fact]
    public void CompressedStereoPacket_DecodesLosslessly()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(StereoCookieHex));
        Assert.Equal(4096, decoder.FrameLength);
        Assert.Equal(2, decoder.Channels);

        var expected = Convert.FromHexString(StereoPacket0PcmHex);
        var decoded = new byte[decoder.MaxBytesPerPacket];
        var written = decoder.DecodePacket(Convert.FromHexString(StereoPacket0Hex), decoded);

        Assert.Equal(expected.Length, written);
        Assert.Equal(expected, decoded.AsSpan(0, written).ToArray()); // zero tolerance — ALAC is lossless
    }

    [Fact]
    public void CompressedStereoPartialFinalPacket_DecodesLosslessly()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(StereoCookieHex));

        var expected = Convert.FromHexString(StereoPacket21PcmHex);
        var decoded = new byte[decoder.MaxBytesPerPacket];
        var written = decoder.DecodePacket(Convert.FromHexString(StereoPacket21Hex), decoded);

        Assert.Equal(2184 * 2 * 2, written); // partial frame: 2184 of 4096 samples
        Assert.Equal(expected.Length, written);
        Assert.Equal(expected, decoded.AsSpan(0, written).ToArray());
    }

    [Fact]
    public void CompressedMonoPacket_DecodesLosslessly()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(MonoCookieHex));
        Assert.Equal(1, decoder.Channels);

        var expected = Convert.FromHexString(MonoPacket0PcmHex);
        var decoded = new byte[decoder.MaxBytesPerPacket];
        var written = decoder.DecodePacket(Convert.FromHexString(MonoPacket0Hex), decoded);

        Assert.Equal(expected.Length, written);
        Assert.Equal(expected, decoded.AsSpan(0, written).ToArray());
    }

    [Fact]
    public void DecoderState_DoesNotLeakBetweenPackets()
    {
        // ALAC frames are independent; decoding other packets in between must
        // not change the result (predictor coefficients etc. are per-frame).
        var decoder = new AlacDecoder(Convert.FromHexString(StereoCookieHex));
        var packet0 = Convert.FromHexString(StereoPacket0Hex);
        var buf = new byte[decoder.MaxBytesPerPacket];

        var n1 = decoder.DecodePacket(packet0, buf);
        var first = buf.AsSpan(0, n1).ToArray();

        decoder.DecodePacket(Convert.FromHexString(StereoPacket21Hex), buf);

        buf.AsSpan().Clear();
        var n2 = decoder.DecodePacket(packet0, buf);
        Assert.Equal(n1, n2);
        Assert.Equal(first, buf.AsSpan(0, n2).ToArray());
    }

    // ------------------------------------------------------------------
    // Magic cookie forms
    // ------------------------------------------------------------------

    [Fact]
    public void Cookie_Raw24_Wrapped36_Wrapped48_AllParse()
    {
        var wrapped48 = Convert.FromHexString(StereoCookieHex);
        var wrapped36 = wrapped48[12..]; // drop the 'frma' atom, keep the 'alac' atom + config
        var raw24 = wrapped48[24..];

        foreach (var cookie in new[] { raw24, wrapped36, wrapped48 })
        {
            var decoder = new AlacDecoder(cookie);
            Assert.Equal(4096, decoder.FrameLength);
            Assert.Equal(16, decoder.BitDepth);
            Assert.Equal(2, decoder.Channels);
            Assert.Equal(44100, decoder.SampleRate);
        }
    }

    [Fact]
    public void Cookie_TooShort_Throws()
    {
        Assert.Throws<ArgumentException>(() => new AlacDecoder(new byte[10]));
        Assert.Throws<ArgumentException>(() => new AlacDecoder(Convert.FromHexString(StereoCookieHex).AsSpan(0, 30).ToArray()));
    }

    // ------------------------------------------------------------------
    // (c) Malformed input — must throw (or return 0), never crash/overread
    // ------------------------------------------------------------------

    [Fact]
    public void EmptyPacket_Throws()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(AirPlayCookieHex));
        Assert.Throws<InvalidDataException>(() => decoder.DecodePacket([], new byte[decoder.MaxBytesPerPacket]));
    }

    [Fact]
    public void TruncatedCompressedPacket_Throws()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(StereoCookieHex));
        var packet = Convert.FromHexString(StereoPacket0Hex);
        var pcm = new byte[decoder.MaxBytesPerPacket];

        Assert.Throws<InvalidDataException>(() => decoder.DecodePacket(packet.AsSpan(0, packet.Length / 2), pcm));
        Assert.Throws<InvalidDataException>(() => decoder.DecodePacket(packet.AsSpan(0, 16), pcm));
    }

    [Fact]
    public void TruncatedVerbatimPacket_Throws()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(AirPlayCookieHex));
        var packet = PackVerbatim(DeterministicPcm(352 * 2));
        var pcm = new byte[decoder.MaxBytesPerPacket];

        Assert.Throws<InvalidDataException>(() => decoder.DecodePacket(packet.AsSpan(0, packet.Length / 2), pcm));
        Assert.Throws<InvalidDataException>(() => decoder.DecodePacket(packet.AsSpan(0, 1), pcm));
    }

    [Fact]
    public void TruncationSweep_NeverCrashes()
    {
        // Every prefix of a real compressed packet must either decode (a prefix
        // can accidentally form a complete frame) or throw InvalidDataException.
        // Managed bounds make genuine overreads impossible; this asserts no
        // other exception type escapes.
        var decoder = new AlacDecoder(Convert.FromHexString(StereoCookieHex));
        var packet = Convert.FromHexString(StereoPacket0Hex);
        var pcm = new byte[decoder.MaxBytesPerPacket];

        for (var len = 1; len < packet.Length; len += len < 128 ? 1 : 61)
        {
            try
            {
                var written = decoder.DecodePacket(packet.AsSpan(0, len), pcm);
                Assert.InRange(written, 0, pcm.Length);
            }
            catch (InvalidDataException)
            {
                // expected for most truncation points
            }
        }
    }

    [Fact]
    public void GarbagePacket_ThrowsOrDecodesWithinBounds()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(AirPlayCookieHex));
        var pcm = new byte[decoder.MaxBytesPerPacket];

        // 0x55... starts with element tag 0b010 (CCE), which is unsupported.
        var garbage = new byte[64];
        Array.Fill(garbage, (byte)0x55);
        Assert.Throws<InvalidDataException>(() => decoder.DecodePacket(garbage, pcm));

        // 0xFF... starts with END; Apple's decoder treats that as a valid,
        // silent frame — ours does too, but it must zero the output.
        var end = new byte[2];
        Array.Fill(end, (byte)0xFF);
        Array.Fill(pcm, (byte)0xAB);
        var written = decoder.DecodePacket(end, pcm);
        Assert.Equal(decoder.MaxBytesPerPacket, written);
        Assert.All(pcm.Take(written), b => Assert.Equal(0, b));
    }

    [Fact]
    public void OutputBufferTooSmall_Throws()
    {
        var decoder = new AlacDecoder(Convert.FromHexString(AirPlayCookieHex));
        var packet = PackVerbatim(DeterministicPcm(352 * 2));
        Assert.Throws<ArgumentException>(() => decoder.DecodePacket(packet, new byte[decoder.MaxBytesPerPacket - 2]));
    }

    // ------------------------------------------------------------------
    // Helpers
    // ------------------------------------------------------------------

    /// <summary>Deterministic pseudo-random s16le PCM (LCG), <paramref name="samples"/> total 16-bit values.</summary>
    private static byte[] DeterministicPcm(int samples)
    {
        var pcm = new byte[samples * 2];
        var seed = 0x13579BDFu;
        for (var i = 0; i < samples; i++)
        {
            seed = seed * 1664525u + 1013904223u;
            BitConverter.TryWriteBytes(pcm.AsSpan(i * 2), (short)(seed >> 16));
        }

        return pcm;
    }

    /// <summary>
    /// Inline replica of the sender's AlacPacker (Streamsemble.AirPlay.Sender.Raop):
    /// 23-bit CPE header declaring an uncompressed payload, 16-bit big-endian
    /// samples, 3-bit end tag.
    /// </summary>
    private static byte[] PackVerbatim(ReadOnlySpan<byte> pcmS16Le)
    {
        var sampleCount = pcmS16Le.Length / 4;
        var output = new byte[(23 + sampleCount * 32 + 3 + 7) / 8];
        var bitPosition = 0;

        void Write(uint value, int bitCount)
        {
            for (var bit = bitCount - 1; bit >= 0; bit--)
            {
                if ((value & (1u << bit)) != 0)
                {
                    output[bitPosition / 8] |= (byte)(0x80 >> (bitPosition % 8));
                }

                bitPosition++;
            }
        }

        Write(1, 3);  // channels - 1? stereo tag used by every RAOP sender
        Write(0, 4);
        Write(0, 8);
        Write(0, 4);
        Write(0, 1);  // has-size
        Write(0, 2);  // unused
        Write(1, 1);  // is-not-compressed

        for (var i = 0; i < pcmS16Le.Length; i += 2)
        {
            // S16LE in, 16-bit big-endian out.
            Write((uint)(pcmS16Le[i + 1] << 8 | pcmS16Le[i]), 16);
        }

        Write(7, 3); // end tag (0b111) — required to close the ALAC frame

        return output;
    }

    // ------------------------------------------------------------------
    // Golden vector constants (generated — see file header)
    // ------------------------------------------------------------------

    // ---- Stereo: kuki + packets from out352.caf ----
    private const string StereoCookieHex = "0000000C66726D61616C616300000024616C616300000000000010000010280A0E02000000004004001588800000AC44";

    // CAF packet 0 (6246 bytes) -> 4096 samples x 2 ch
    private const string StereoPacket0Hex =
        "";

    private const string StereoPacket0PcmHex =
        "";

    // CAF packet 21 (3399 bytes) -> 2184 samples x 2 ch
    private const string StereoPacket21Hex =
        "";

    private const string StereoPacket21PcmHex =
        "";


    // ---- Mono: kuki + packets from outmono.caf ----
    private const string MonoCookieHex = "0000000C66726D61616C616300000024616C616300000000000010000010280A0E01000000002004000AC4400000AC44";

    // CAF packet 0 (3122 bytes) -> 4096 samples x 1 ch
    private const string MonoPacket0Hex =
        "";

    private const string MonoPacket0PcmHex =
        "";
}
